<?php require __DIR__.'/includes/pawn_bootstrap.php'; if(!pawn_permission($conn,'open')){http_response_code(403);die('Access denied.');}$theme=pawn_theme($conn,$businessId);$q=trim((string)($_GET['search']??''));$status=(string)($_GET['status']??'');$page=max(1,(int)($_GET['page']??1));$per=20;$off=($page-1)*$per;$where='pe.business_id=? AND pe.branch_id=?';$types='ii';$args=[$businessId,$branchId];if($q!==''){$where.=' AND (pe.pawn_no LIKE ? OR c.customer_name LIKE ? OR c.mobile LIKE ?)';$like='%'.$q.'%';$types.='sss';array_push($args,$like,$like,$like);}if(in_array($status,['Draft','Active','Partially Paid','Closed','Auctioned','Cancelled'],true)){$where.=' AND pe.status=?';$types.='s';$args[]=$status;}$sql="SELECT pe.*,c.customer_name,c.mobile,pc.category_name FROM pawn_entries pe JOIN customers c ON c.id=pe.customer_id AND c.business_id=pe.business_id JOIN pawn_categories pc ON pc.id=pe.pawn_category_id WHERE $where ORDER BY pe.id DESC LIMIT ?,?";$types.='ii';$args[]=$off;$args[]=$per;$st=$conn->prepare($sql);$st->bind_param($types,...$args);$st->execute();$rows=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$st=$conn->prepare('SELECT COUNT(*) total,COALESCE(SUM(principal_amount),0) issued,COALESCE(SUM(balance_principal),0) outstanding,SUM(status="Active" OR status="Partially Paid") active FROM pawn_entries WHERE business_id=? AND branch_id=?');$st->bind_param('ii',$businessId,$branchId);$st->execute();$summary=$st->get_result()->fetch_assoc();$st->close();$pageTitle='Pawn Entries';$businessName=$_SESSION['business_name']??'Jewellery ERP';?>
<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=pawn_e($businessName)?> - Pawn Entries</title><?php include 'includes/links.php'; include __DIR__.'/includes/pawn_styles.php';?></head><body><?php include 'includes/sidebar.php';?><main class="app-main"><?php include 'includes/nav.php';?><div class="content-wrap"><div class="row g-3 mb-3"><div class="col-md-3"><div class="stat"><small>Total Pawns</small><strong><?=(int)$summary['total']?></strong></div></div><div class="col-md-3"><div class="stat"><small>Active</small><strong><?=(int)$summary['active']?></strong></div></div><div class="col-md-3"><div class="stat"><small>Issued Value</small><strong>₹<?=pawn_money($summary['issued'])?></strong></div></div><div class="col-md-3"><div class="stat"><small>Outstanding</small><strong>₹<?=pawn_money($summary['outstanding'])?></strong></div></div></div><div class="pawn-card"><div class="pawn-head"><div><div class="pawn-title">Pawn Broking</div><div class="small text-muted">Manage pledges, interest, repayments and release.</div></div><?php if(pawn_permission($conn,'create')):?><a class="btn btn-theme" href="pawn-entry.php"><i class="fa-solid fa-plus me-2"></i>New Pawn</a><?php endif?></div><div class="section"><form class="row g-2"><div class="col-md-7"><input class="form-control" name="search" value="<?=pawn_e($q)?>" placeholder="Search pawn no, customer or mobile"></div><div class="col-md-3"><select class="form-select" name="status"><option value="">All statuses</option><?php foreach(['Draft','Active','Partially Paid','Closed','Auctioned','Cancelled'] as $s):?><option <?=$status===$s?'selected':''?>><?=pawn_e($s)?></option><?php endforeach?></select></div><div class="col-md-2"><button class="btn btn-theme w-100">Filter</button></div></form></div><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Pawn No</th><th>Date</th><th>Customer</th><th>Category</th><th class="text-end">Principal</th><th class="text-end">Balance</th><th>Status</th><th></th></tr></thead><tbody><?php if(!$rows):?><tr><td colspan="8" class="text-center py-5 text-muted">No pawn entries found.</td></tr><?php endif;foreach($rows as $r):?><tr><td><strong><?=pawn_e($r['pawn_no'])?></strong></td><td><?=pawn_e(date('d M Y',strtotime($r['pawn_date'])))?></td><td><?=pawn_e($r['customer_name'])?><br><small class="text-muted"><?=pawn_e($r['mobile'])?></small></td><td><?=pawn_e($r['category_name'])?></td><td class="text-end">₹<?=pawn_money($r['principal_amount'])?></td><td class="text-end">₹<?=pawn_money($r['balance_principal'])?></td><td><span class="status s-<?=pawn_e(str_replace(' ','-',$r['status']))?>"><?=pawn_e($r['status'])?></span></td><td class="text-end"><a class="btn btn-light btn-sm" href="pawn-view.php?id=<?=(int)$r['id']?>">View</a></td></tr><?php endforeach?></tbody></table></div></div><?php include 'includes/footer.php';?></div></main><?php include 'includes/script.php';?><script src="assets/js/script.js"></script></body></html>
